import{_ as a,p as e,q as s,a1 as n}from"./framework-5866ffd3.js";const i={},l=n(`<h1 id="tailf" tabindex="-1"><a class="header-anchor" href="#tailf" aria-hidden="true">#</a> tailf</h1><p>在屏幕上显示指定文件的末尾若干行内容，通常用于日志文件的跟踪输出</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p>tailf命令几乎等同于<code>tail -f</code>，严格说来应该与<code>tail --follow=name</code>更相似些。当文件改名之后它也能继续跟踪，特别适合于日志文件的跟踪（follow the growth of a log file）。与<code>tail -f</code>不同的是，如果文件不增长，它不会去访问磁盘文件。tailf特别适合那些便携机上跟踪日志文件，因为它能省电，因为减少了磁盘访问。tailf命令不是个脚本，而是一个用C代码编译后的二进制执行文件，某些Linux安装之后没有这个命令。</p><p>tailf和tail -f的区别</p><ol><li>tailf 总是从文件开头一点一点的读， 而tail -f 则是从文件尾部开始读</li><li>tailf check文件增长时，使用的是文件名， 用stat系统调用；而tail -f 则使用的是已打开的文件描述符； 注：tail 也可以做到类似跟踪文件名的效果； 但是tail总是使用fstat系统调用，而不是stat系统调用；结果就是：默认情况下，当tail的文件被偷偷删除时，tail是不知道的，而tailf是知道的。</li></ol><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>tailf logfile <span class="token comment"># 动态跟踪日志文件logfile，最初的时候打印文件的最后10行内容。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>-n, <span class="token parameter variable">--lines</span> NUMBER  <span class="token comment"># 输出最后数行</span>
<span class="token parameter variable">-NUMBER</span>             <span class="token comment"># 与NUMBER相同 \`-n NUMBER&#39;</span>
-V, <span class="token parameter variable">--version</span>       <span class="token comment"># 输出版本信息并退出</span>
-h, <span class="token parameter variable">--help</span>          <span class="token comment"># 显示帮助并退出</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h3><p>目标：指定目标日志。</p><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>tailf log/WEB.LOG 
tailf <span class="token parameter variable">-n</span> <span class="token number">5</span> log2014.log   <span class="token comment"># 显示文件最后5行内容</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div>`,14),t=[l];function d(r,c){return e(),s("div",null,t)}const h=a(i,[["render",d],["__file","tailf.html.vue"]]);export{h as default};
